        List<Future<?>> clears = new ArrayList<>();
        for (int i = 0; i < workerCount; i++) {
            clears.add(workers.submit(ThreadBridge::clear));
        }
        for (Future<?> clear : clears) {
            clear.get(1, TimeUnit.SECONDS);
        }
        revisions.close();
        workers.shutdown();
        workers.awaitTermination(5, TimeUnit.SECONDS);
